/* ANTHROPOLOGY SPECIFIC STYLES */
.anthro-unit-header { text-align: center; margin-bottom: 30px; }
.anthro-unit-label { display: block; font-size: 18px; margin-bottom: 5px; }
.anthro-unit-title { display: block; font-size: 24px; font-weight: bold; margin-bottom: 5px; }
.anthro-unit-hours { display: block; font-size: 16px; font-weight: bold; }

.anthro-callout { display: flex; align-items: flex-start; gap: 20px; border: 1px solid #000; padding: 15px; margin: 20px 0; }
.anthro-callout-icon { width: 80px; flex-shrink: 0; }
.anthro-callout-icon img { width: 100%; height: auto; }
.anthro-callout-content { flex-grow: 1; }
.anthro-callout-title { font-weight: bold; margin-bottom: 10px; display: block; font-size: 16px; }

.anthro-list { list-style: none; padding-left: 0; margin: 15px 0; }
.anthro-list-item { display: flex; align-items: flex-start; gap: 10px; margin-bottom: 8px; text-align: justify; }
.anthro-bullet-img { width: 22px; flex-shrink: 0; margin-top: 2px; }

/* CSS Feathered Checkmark */
.checkmark-feathered {
    width: 14px; height: 8px; 
    border-left: 3px solid #000; border-bottom: 3px solid #000;
    transform: rotate(-45deg) skewX(-10deg);
    margin-top: 4px; margin-left: 4px; flex-shrink: 0;
}

.anthro-footnote { font-size: 12px; margin-top: 15px; border-top: 1px solid #000; padding-top: 5px; width: 100%; }

if (pageData.requires_manual_image === true) {
    const flag = document.createElement('div');
    flag.className = 'manual-flag';
    flag.innerText = '🖼️ MANUAL IMAGE REQUIRED';
    pageDiv.appendChild(flag);
}

pageData.content.forEach(item => {
    const element = document.createElement('div');

    if (item.type === 'unit-header') {
        element.className = 'anthro-unit-header';
        element.innerHTML = `<span class="anthro-unit-label">Unit ${item.number || ''}</span><span class="anthro-unit-title">${item.title || ''}</span><span class="anthro-unit-hours">Study Hours: ${item.hours || ''}</span>`;
    }
    else if (item.type === 'callout-box') {
        element.className = 'anthro-callout';
        const iconFile = item.icon === 'books' ? 'icon-books.png' : 'icon-question-man.png';
        let listHtml = '';
        if (item.items) listHtml = '<ul>' + item.items.map(i => `<li>${i}</li>`).join('') + '</ul>';
        element.innerHTML = `
            <div class="anthro-callout-icon"><img src="assets/${iconFile}"></div>
            <div class="anthro-callout-content">
                <span class="anthro-callout-title">${item.label || ''}</span>
                ${item.body || ''}
                ${listHtml}
            </div>`;
    }
    else if (item.type === 'bullet-list') {
        element.className = 'anthro-list';
        const listItems = item.items || [];
        listItems.forEach(text => {
            const row = document.createElement('div');
            row.className = 'anthro-list-item';
            if (item.bullet === 'checkmark') {
                row.innerHTML = `<div class="checkmark-feathered"></div><div>${text}</div>`;
            } else {
                const bImg = item.bullet === 'swirl' ? 'bullet-swirl.png' : 'bullet-spark.png';
                row.innerHTML = `<img src="assets/${bImg}" class="anthro-bullet-img"><div>${text}</div>`;
            }
            element.appendChild(row);
        });
    }
    else if (item.type === 'paragraph') {
        element.className = 'p-block';
        element.innerHTML = item.body;
    }
    else if (item.type === 'header') {
        element.className = 'h-block';
        element.innerHTML = item.body;
    }
    else if (item.type === 'table') {
        let t = '<table>';
        item.rows.forEach(row => {
            t += '<tr>' + row.map(c => `<td>${c}</td>`).join('') + '</tr>';
        });
        element.innerHTML = t + '</table>';
    }
    else if (item.type === 'footnote') {
        element.className = 'anthro-footnote';
        element.innerHTML = `<sup>${item.number || ''}</sup> ${item.body}`;
    }
    else if (item.type === 'spacer') {
        element.style.flexGrow = item.flex || '0';
        element.style.height = item.height || '0px';
    }
    else if (item.type === 'footer') {
        element.className = 'footer';
        element.innerText = item.val;
    }

    // Apply styles if present
    if (item.style) {
        Object.assign(element.style, item.style);
    }

    pageDiv.appendChild(element);
});

