package com.conduit.nexus

import android.content.ClipboardManager
import android.content.Context
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.text.BasicTextField
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.TextStyle
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun TextEditorScreen(viewModel: ConduitViewModel, onBack: () -> Unit) {
    val context = LocalContext.current
    val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
    val hasChanges = viewModel.editorText != viewModel.originalText

    Column(modifier = Modifier.fillMaxSize().background(MaterialTheme.colorScheme.background)) {
        TopAppBar(
            title = { Text(viewModel.editingFile?.name ?: "Editor", fontSize = 16.sp, fontFamily = FontFamily.Monospace) },
            navigationIcon = {
                IconButton(onClick = onBack) {
                    Icon(Icons.Default.Close, null)
                }
            },
            actions = {
                if (!viewModel.isEditLocked) {
                    IconButton(onClick = { viewModel.editorText = "" }) {
                        Icon(Icons.Default.DeleteForever, null, tint = Color.Red)
                    }
                    IconButton(onClick = {
                        val clip = clipboard.primaryClip?.getItemAt(0)?.text?.toString() ?: ""
                        viewModel.editorText = clip
                    }) {
                        Icon(Icons.Default.ContentPaste, null, tint = MaterialTheme.colorScheme.primary)
                    }
                }

                IconButton(onClick = { viewModel.isEditLocked = !viewModel.isEditLocked }) {
                    Icon(
                        if (viewModel.isEditLocked) Icons.Default.Edit else Icons.Default.EditOff,
                        null, 
                        tint = if (viewModel.isEditLocked) Color.Gray else MaterialTheme.colorScheme.primary
                    )
                }

                Button(
                    onClick = { viewModel.saveCurrentFile() },
                    enabled = hasChanges,
                    modifier = Modifier.padding(end = 8.dp),
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF4CAF50))
                ) {
                    Text("Save")
                }
            }
        )

        Box(modifier = Modifier.fillMaxSize().padding(16.dp)) {
            BasicTextField(
                value = viewModel.editorText,
                onValueChange = { if (!viewModel.isEditLocked) viewModel.editorText = it },
                modifier = Modifier.fillMaxSize(),
                textStyle = TextStyle(
                    color = Color.White,
                    fontFamily = FontFamily.Monospace,
                    fontSize = 14.sp
                ),
                readOnly = viewModel.isEditLocked
            )
        }
    }
}

